import{_ as a,o as p,c as i,a2 as e}from"./chunks/framework.M-AdQQii.js";const d=JSON.parse('{"title":"1.12 妖精管家","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 妖精管家是代替你干农活儿的，像收地、挤奶、采果、剃毛、跑商等，不需要你费时间打理这些，材料准备好交给它处理就行了。 想让妖精管家帮你种地，肯定需要准备一些东西。 1）一个可以刻印的建筑物 ","frontmatter":{"title":"1.12 妖精管家","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 妖精管家是代替你干农活儿的，像收地、挤奶、采果、剃毛、跑商等，不需要你费时间打理这些，材料准备好交给它处理就行了。 想让妖精管家帮你种地，肯定需要准备一些东西。 1）一个可以刻印的建筑物 ","outline":"deep"},"headers":[],"relativePath":"life/1-12.md","filePath":"life/1-12.md","lastUpdated":null}'),t={name:"life/1-12.md"};function g(u,s,l,r,o,f){return p(),i("div",null,[...s[0]||(s[0]=[e('<h1 id="_1-12-妖精管家" tabindex="-1">1.12 妖精管家 <a id="s120-e8a6efc8"></a> <a class="header-anchor" href="#_1-12-妖精管家" aria-label="Permalink to &quot;1.12 妖精管家 &lt;a id=&quot;s120-e8a6efc8&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_1-12-1-妖精管家是什么" tabindex="-1">1.12.1 妖精管家是什么 <a id="s121-47a87be1"></a> <a class="header-anchor" href="#_1-12-1-妖精管家是什么" aria-label="Permalink to &quot;1.12.1 妖精管家是什么 &lt;a id=&quot;s121-47a87be1&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>妖精管家是代替你干农活儿的，像收地、挤奶、采果、剃毛、跑商等，不需要你费时间打理这些，材料准备好交给它处理就行了。</p><p>想让妖精管家帮你种地，肯定需要准备一些东西。</p><p>1）一个可以刻印的建筑物</p><p>2）菜田或者凉亭图纸</p><p>3）妖精管家每次干活的劳动力，由主人你提供</p><p>4、妖精管家不是白干的，需要支付费用，这个不是金币也不是点券</p><p>5、就是让他所做农活的材料或者种子这些。</p><h2 id="_1-12-2-妖精管家的刻印" tabindex="-1">1.12.2 妖精管家的刻印 <a id="s122-71c46f76"></a> <a class="header-anchor" href="#_1-12-2-妖精管家的刻印" aria-label="Permalink to &quot;1.12.2 妖精管家的刻印 &lt;a id=&quot;s122-71c46f76&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>想使用妖精管家，必须先刻印（直接理解为激活），刻印只需要刻印1 次就可以永久使用。刻印只能刻印自己的建筑物。</p><p>一般的建筑房屋都是可以刻印的，如：茅草屋、树屋、糖果屋、宅邸、豆树屋等等，小型建筑像5 税票的加工台、蓝屋顶仓库也都是可以刻印的。</p><p>到自己的建筑门口，找到铭牌，铭牌一般都是门的旁边，树屋在一层，在铭牌前，</p><p>有3 个按钮，按H。（如果角度不对只有开关门，转一下身体方向找找角度）刻印需要交20 张税票作为门槛费用。如果你想更换刻印的房子仍然需要再次提交20 税票。</p><p>成功刻印后，铭牌旁边会出现妖精管家，如下图：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1601.jpeg" alt="图示：1.12.2 妖精管家的刻印" loading="lazy"></figure><h2 id="_1-12-3-妖精管家面板介绍" tabindex="-1">1.12.3 妖精管家面板介绍 <a id="s123-7c33bab6"></a> <a class="header-anchor" href="#_1-12-3-妖精管家面板介绍" aria-label="Permalink to &quot;1.12.3 妖精管家面板介绍 &lt;a id=&quot;s123-7c33bab6&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>按下SHIFT+H 键可以唤出妖精管家面板。</p><p>蓝色框部分：可以切换妖精管家面板、菜地面板和贸易面板。</p><p>红色框部分：生产费用：生产费用每周一0 点会赠送3 次500 点费用，需要自己点+号领取，如果免费的领取了，也用完了还不够使，就需要用约定的果实（可以从商城购买，点券可以购买多个，10 鲁鲁币每天可以买1 个）增加制作费用。</p><p>劳动力：劳动力是由主人的劳动力提供的，点击+号，点最多，输入框内是多少劳动力，就从你当前劳动力扣除。</p><p>经验条：下面的经验条和数字就是你妖精管家的等级和经验条，等级越高，获得的能力越强大。</p><p>绿色框是跟妖精管家熟练度相关的，熟练度越高，生产时间越短，额外获得产物越多。记得升级后点上箭头提升等级，正在工作的管家不能提升熟练度。</p><p>小窍门：如果你要管家种树，</p><p>那全点伐木，升到满，点适用。</p><p>下一次要种大米，先重置，把农</p><p>业点到满，然后适用，如果生活</p><p>点或者经济允许，在生活点商店</p><p>给管家买5 件装备，可以增加熟</p><p>练度，手头宽裕的可以买商城更</p><p>好的。</p><p>妖精管家等级开放项目如右：</p><p>第一次装备菜地流程如下：</p><p>红色框部分，是设置地皮的。</p><p>绿色框是要登记的作物，是采农作物，还是摘果，还是挤奶，都在这里添加。</p><p>蓝色是生产过程剩余时间，和取消生产的地方。</p><p>1、6、15 级分别可以添加1、2、3 个菜田，16 级时，可以用养殖场水田了，可以混合使用，比如2 个养殖场1 个菜地等。</p><p>菜田包括稻草人（月光稻草人、调皮稻草人等8X8）、南瓜头（改良型南瓜头、</p><p>月光南瓜头、调皮南瓜头等16X16）、凉亭（月光凉亭、朝阳凉亭等24X24），养殖场包括商城和礼包贩卖的水田，水上住宅除外。</p><p>只受数量限制，所以种植面积越大越好。</p><p>点击额外登记按钮，将背包里的图纸右键添加进来，点确认，这样就添加进来一个菜地了。</p><p>选择下拉列表可以查看和去除菜地，去除后直接到你背包里。</p><p>调整好菜地（养殖场）后，就可以选要生产的东西了，如果想挤奶，你就买好奶牛，想摘果，就买好果树，想要农作物就买种子，如果想买正好的，一定要注意你菜地的种植数量，和你农作物的占地面积。</p><p>红色框内是你添加进去所有菜地的种植面积，图纸上可以看到种植的面积。</p><p>绿色框是你要生产作物的总信息。</p><p>蓝色框是单个作物的信息。</p><p>记得把数量最大化登记。</p><p>动物相关的剃毛、挤奶等，只能生产10 次，第10 次按屠宰算。果树只能生产5次，第5 次按伐木算。</p><p>一切就绪后，点击登记，妖精管家就开始工作了，等着收东西就行了，会以邮件方式发送给你。如果取消，是不会返还种子、树苗的。</p><p>一般来说比较推荐用妖精管家来养牛，比较省心。</p><p>不推荐搞贸易。不吃熟练度的熟练度和收益加成（新版本享受妖精的熟练度收益加成，但依然不推荐），而且时间特别久，还需要搞一辆拖拉机给妖精管家，巨亏。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1607.jpeg" alt="图示：1.12.3 妖精管家面板介绍" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1612.jpeg" alt="图示：1.12.3 妖精管家面板介绍" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1613.jpeg" alt="图示：1.12.3 妖精管家面板介绍" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1614.jpeg" alt="图示：1.12.3 妖精管家面板介绍" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1619.jpeg" alt="图示：1.12.3 妖精管家面板介绍" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1620.jpeg" alt="图示：1.12.3 妖精管家面板介绍" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1625.jpeg" alt="图示：1.12.3 妖精管家面板介绍" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1630.jpeg" alt="图示：1.12.3 妖精管家面板介绍" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1631.jpeg" alt="图示：1.12.3 妖精管家面板介绍" loading="lazy"></figure><h2 id="_1-12-4-妖精管家装备" tabindex="-1">1.12.4 妖精管家装备 <a id="s124-b7f866cc"></a> <a class="header-anchor" href="#_1-12-4-妖精管家装备" aria-label="Permalink to &quot;1.12.4 妖精管家装备 &lt;a id=&quot;s124-b7f866cc&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>管家装备分为2 种：</p><p>1）生活点购买的</p><p>2）点券购买的</p><p>点券买的性能会更加好，</p><p>而且1）升级后会变成跑商的</p><p>装备，而2）可以买指定类型</p><p>的熟练度装备，可以用点券买</p><p>的觉醒券来觉醒。觉醒后属性</p><p>为对应的+7000，其他熟练度</p><p>+5000。</p><p>1）购买方式如右图：</p><p>升级方式如下：</p><p>2）的购买方式如下：</p><p>按N 键唤出商城界面后：</p><p>点券基础装备如下：</p><p>觉醒后如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1636.jpeg" alt="图示：1.12.4 妖精管家装备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1642.jpeg" alt="图示：1.12.4 妖精管家装备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1643.jpeg" alt="图示：1.12.4 妖精管家装备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1644.jpeg" alt="图示：1.12.4 妖精管家装备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1649.jpeg" alt="图示：1.12.4 妖精管家装备" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1650.jpeg" alt="图示：1.12.4 妖精管家装备" loading="lazy"></figure>',84)])])}const _=a(t,[["render",g]]);export{d as __pageData,_ as default};
